// Safety check: validate host and command before SSH
const allowedHosts = (process.env.SSH_ALLOWED_HOSTS || '').split(',').map(h => h.trim().toLowerCase()).filter(Boolean);
const host = ($input.first().json.host || '').trim().toLowerCase();
const command = ($input.first().json.command || '').trim();

// Blocked command patterns — destructive or dangerous operations
const blockedPatterns = [
  /rm\s+-rf/i,
  /mkfs/i,
  /dd\s+if/i,
  /:\(\)/,           // fork bomb
  />\s*\/dev\/sd/i,  // disk overwrite
  /shutdown/i,
  /reboot/i,
  /halt/i,
  /poweroff/i,
  /passwd/i,
  /userdel/i,
  /chmod\s+777/i,
  /curl.*\|.*sh/i,   // curl pipe to shell
  /wget.*\|.*sh/i,
];

if (!host) throw new Error('run_command: no host specified');
if (!command) throw new Error('run_command: no command specified');
if (!allowedHosts.includes(host)) {
  throw new Error(`run_command: host '${host}' is not in SSH_ALLOWED_HOSTS (${allowedHosts.join(', ')})`);
}
for (const pattern of blockedPatterns) {
  if (pattern.test(command)) {
    throw new Error(`run_command: command blocked by safety filter: ${command}`);
  }
}

return [{ json: { host, command } }];

// Resolve SSH connection details from env vars
const host = $input.first().json.host.toUpperCase();
const sshHost = process.env[`SSH_HOST_${host}`];
const sshUser = process.env[`SSH_USER_${host}`];
const sshKey  = process.env[`SSH_KEY_${host}`];

if (!sshHost) throw new Error(`run_command: SSH_HOST_${host} not set in environment`);
if (!sshUser) throw new Error(`run_command: SSH_USER_${host} not set in environment`);

return [{ json: {
  host: $input.first().json.host,
  command: $input.first().json.command,
  sshHost,
  sshUser,
  sshKey: sshKey || null
} }];

const result = $input.first().json;
const stdout = result.stdout || '';
const stderr = result.stderr || '';
const exitCode = result.code ?? 0;

let output = stdout.trim();
if (stderr.trim()) output += (output ? '\n' : '') + `STDERR: ${stderr.trim()}`;
if (exitCode !== 0) output += `\nExit code: ${exitCode}`;

return [{ json: { output: output || '(no output)' } }];
